def _copy_payload(root: Path) -> None:
    for rel, content in PAYLOAD_FILES.items():
        path = root / rel
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8", newline="\n")


def _patch_legacy_h1_test(root: Path) -> bool:
    path = root / "tests/test_production_readiness_evidence_refresh_4B436629E_H1.py"
    if not path.exists():
        return False
    text = path.read_text(encoding="utf-8")
    new_text = text.replace(STALE_DECISION, ACTUAL_DECISION)
    if new_text != text:
        backup_dir = root / "tools" / f"_patch_backup_{CONTRACT_VERSION}_{datetime.now(timezone.utc).strftime('%Y%m%dT%H%M%SZ')}"
        backup_dir.mkdir(parents=True, exist_ok=True)
        shutil.copy2(path, backup_dir / "test_production_readiness_evidence_refresh_4B436629E_H1.py")
        path.write_text(new_text, encoding="utf-8", newline="\n")
        return True
    return ACTUAL_DECISION in text and STALE_DECISION not in text


def _load_h3_report(root: Path) -> dict:
    sys.path.insert(0, str(root / "tools"))
    try:
        spec = importlib.util.spec_from_file_location(
            "check_4B436629E_H3_production_readiness_legacy_test_compat",
            root / "tools" / "check_4B436629E_H3_production_readiness_legacy_test_compat.py",
        )
        if spec is None or spec.loader is None:
            raise RuntimeError("Cannot load H3 checker")
        module = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(module)
        return module.build_report(root)
    finally:
        while str(root / "tools") in sys.path:
            sys.path.remove(str(root / "tools"))


def main() -> int:
    root = Path.cwd()
    _load_payload()
    _copy_payload(root)
    patched_test = _patch_legacy_h1_test(root)
    report = _load_h3_report(root)
    report["patched_legacy_h1_test"] = bool(patched_test)
    print(json.dumps(report, ensure_ascii=False, indent=2, sort_keys=True))
    print(f"{CONTRACT_VERSION} production readiness legacy test compatibility hotfix applied")
    print(f" - patched_legacy_h1_test: {patched_test}")
    for key, value in report.get("checks", {}).items():
        print(f" - {key}: {value}")
    print(" - runtime_overlay_activation_performed: False")
    print(" - training_performed: False")
    print(" - reload_performed: False")
    print(" - trading_action_performed: False")
    print(" - paper_live_order_enablement_present: False")
    return 0 if report.get("ok") else 2


if __name__ == "__main__":
    raise SystemExit(main())
